/**
 * @autom8y/contente-tokens — barrel entrypoint.
 *
 * The single owned source of truth for the Contente CLIENT-FACING brand.
 *
 *   - `tokens`        the generated DTCG projection (Contente's own key-set) —
 *                     the structured surface for a Path-C client app.
 *   - `cssDir`        absolute path to the canonical CSS sheet directory.
 *   - `cssPath(name)` absolute path to one canonical sheet (e.g. 'colors.css').
 *
 * CSS consumers (the offline deck build) should resolve sheets via the package
 * `exports` map (e.g. `@autom8y/contente-tokens/css/colors`) or `cssDir`.
 * App consumers (Path-C) import `tokens` for structured lookups.
 *
 * The CSS is CANONICAL; `tokens.json` is GENERATED one-way from it
 * (scripts/generate.mjs). Never hand-edit tokens.json.
 */

import tokens from './tokens.json' with { type: 'json' };
import { fileURLToPath } from 'node:url';
import { dirname, join } from 'node:path';

const __dir = dirname(fileURLToPath(import.meta.url));

/** Absolute directory of the canonical brand CSS sheets. */
export const cssDir = join(__dir, 'src', 'css');

/**
 * Absolute path to one canonical CSS sheet.
 * @param {string} name e.g. 'colors.css', 'styles.css'
 * @returns {string}
 */
export const cssPath = (name) => join(cssDir, name);

/** The DTCG token projection (Contente's own key-set, fe-skeleton shape). */
export { tokens };

export default tokens;
